// Detect index errors
const rows = $input.all().map(i => i.json);
const today = rows[0];
const yesterday = rows[1];

const alerts = [];

// Check for new errors
if (today && today.error_change > 0) {
  alerts.push({
    type: 'index_error',
    severity: today.error_change > 10 ? 'critical' : 'warning',
    title: `${today.error_change} new index errors detected`,
    message: `Total errors: ${today.error_count}. Previous: ${today.error_count - today.error_change}`,
    metadata: JSON.stringify({ error_count: today.error_count, change: today.error_change })
  });
}

// Check for significant indexed drop
if (today && today.indexed_change < -50) {
  alerts.push({
    type: 'index_drop',
    severity: 'critical',
    title: `${Math.abs(today.indexed_change)} pages dropped from index`,
    message: `Indexed pages: ${today.indexed_count}. Previous: ${today.prev_indexed}`,
    metadata: JSON.stringify({ indexed_count: today.indexed_count, change: today.indexed_change })
  });
}

return [{ json: { alerts, has_alerts: alerts.length > 0 } }];

const data = $input.first().json;
const alerts = data.alerts;

let message = ':warning: *GSC Index Alert*\n\n';
alerts.forEach(a => {
  const icon = a.severity === 'critical' ? ':red_circle:' : ':large_yellow_circle:';
  message += `${icon} *${a.title}*\n${a.message}\n\n`;
});

return [{ json: { message } }];
